const Q_CHEMISTRY_2000=[{"id": "objective>Chemistry>2000>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture of iodine and sulphur crystals can be separated by treating with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">water to filter off sulphur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) sulphide to filter off iodine </div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanoic acid to filter off sulphur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">methanol to filter off iodine</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To a mixture of iodine crystals and sulphur powder, add carbon disulphide solution and stir( it will be observed that the sulphur will dissolve leaving behind the undissolved iodine crystals) <br/> for further separation, pass the mixture  through a filter paper(a colloidal solution of sulphur in carbon disulphide gets separated in a different container as the filtrate while the undissolved iodine crystal is left behind as the residue). </div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2000>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sieving is a technique used to separate mixtures containing solid particles of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">small sizes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">large sizes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">different sizes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the same sizes</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sieving is a technique used to separate mixtures containing solid particles of different sizes. The mixture is passed through a sieve or a series of sieves with different sized holes. The smaller particles pass through the sieve, while the larger particles remain on top.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>2000>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds is composed of Al, Si, O and H?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">epsom salt</div>", "<div style=\"font-family:Cambria;font-size:17px;\">limestone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">clay</div>", "<div style=\"font-family:Cambria;font-size:17px;\">urea</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Clay is composed of Al, Si, O and H. Epsom salt is composed of magnesium, sulfur, and oxygen. Limestone is composed of calcium, carbon, and oxygen. Urea is composed of carbon, nitrogen, oxygen, and hydrogen.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2000>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">50cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of carbon (II) oxide was exploded with 150cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of air containing 20% oxygen by volume. Which of the reactants was in excess?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Carbon (II) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon (IV) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nitrogen</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2CO + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 2CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 50 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> → 25 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  20% of 150cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 30cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  30cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> is available, yet just 25cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> is required. <br/> Therefore oxygen is in excess.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2000>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many moles of HCL will be required to react with potassium heptaoxodichromate(VI) to produce 3 moles of chlorine?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">14</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12</div>", "<div style=\"font-family:Cambria;font-size:17px;\">11</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The balanced chemical equation for the reaction between HCl and potassium heptaoxodichromate(VI) is: K<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>Cr<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">7</span> + 14HCl -> 2KCl + 2CrCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> + 3Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + 7H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O. From this equation, we can see that 14 moles of HCl are required to produce 3 moles of Cl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>.</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2000>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ratio of the initial to the final pressure of a given mass of gas is 1:1.5. Calculate the final volume of the gas if the initial volume was 300cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at the same temperature. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">120cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">450cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">750cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">We use P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/>  we are to find V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = (1 ×300)/1.5  = 200cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : COMBINED GAS LAW,MOLAR VOLUME AND ATOMICITY OF GASES"}, {"id": "objective>Chemistry>2000>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The partial pressure of oxygen in a sample of air is 452mmHg and the total pressure is 780mmHg. What is the mole fraction of oxygen?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.203</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.579</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.030</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5.790</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">mole fraction = partial pressure/total pressure, x<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">i</span>   P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>/P = 452/780 = 0.579</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2000>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The fundamental difference between the three states of matter is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">shape of their particle</div>", "<div style=\"font-family:Cambria;font-size:17px;\">number of particles in each state</div>", "<div style=\"font-family:Cambria;font-size:17px;\">shape of the container they occupy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">degree of movement of their particle</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The fundamental difference between the three states of matter (solid, liquid, and gas) is the degree of movement of their particles. In solids, the particles are closely packed and can only vibrate in place. In liquids, the particles can move past each other but are still closely packed. In gases, the particles are far apart and move freely.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2000>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statement is correct about the periodic table?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Elements in the same period have the same number of valence electrons </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The valence electron of the element in the same period increase progressively across the period</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Element in the same group have the same number of electron shells</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the non-metallic properties of the elements tend to decrease across each period</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the periodic table, the valence electrons of the elements in the same period increase progressively across the period. This is because as you move from left to right across a period, each element has one more proton and one more electron than the previous element. The additional electron goes into the same outermost shell, which is why the number of valence electrons increases.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2000>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The electron configuration of <span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">22</span>X<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> ion is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3d<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>4s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3d<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>4s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electron configuration of a neutral atom with atomic number 22 (which is Titanium) is 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>4s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3d<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>. When it loses 2 electrons to form a 2+ ion, the two 4s electrons are the ones that are lost, leaving the configuration as 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>3p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span>3d<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2000>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following type of bonding does not involve the formation of new substance?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Metallic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Co-ordinate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electrovalent</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Metallic bond is the bonding between atoms within metals characterized by a \"sea of delocalized electrons\" that are free to move throughout the structure. This bond involves the sharing of these free electrons among a lattice of positive metal ions. The delocalized electrons act as a glue holding the metal ions together and giving the metal its characteristic properties, such as electrical conductivity, malleability, ductility, and strength. <br/>  <img src=\"2000/k40.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2000>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The knowledge of half life can be used to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">create an element</div>", "<div style=\"font-family:Cambria;font-size:17px;\">detect an element</div>", "<div style=\"font-family:Cambria;font-size:17px;\">split an element</div>", "<div style=\"font-family:Cambria;font-size:17px;\">irradiate an element</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The half-life of a radioactive element is the time it takes for half of the atoms in a sample to decay. This property can be used to detect the presence of the element, as the rate of decay can be measured.</div>", "topic": "NUCLEAR CHEMISTRY : RADIOACTIVITY"}, {"id": "objective>Chemistry>2000>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shapes of CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>, H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O and CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> respectively are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">bent, linear and tetrahedral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bent, tetrahedral and linear</div>", "<div style=\"font-family:Cambria;font-size:17px;\">linear, bent and tetrahedral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tetrahedral, linear and bent</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The shape of a molecule is determined by the arrangement of the electron pairs around the central atom. CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is linear because the two double bonds are on opposite sides of the carbon atom. H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O is bent because the two hydrogen atoms and the two lone pairs of electrons on the oxygen atom are arranged in a tetrahedral shape, but we only see the atoms, not the lone pairs. CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> is tetrahedral because the four hydrogen atoms are equally spaced around the carbon atom.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SHAPES OF SIMPLE MOLECULES"}, {"id": "objective>Chemistry>2000>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The distance between the nuclei of chlorine atoms in a chlorine molecule is 0.194mm. The atomic radius of chlorine atom is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.097mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.194mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.388mm</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.388mm</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">the distance between two covalent bonded nuclei is related to the the radius as distance=2 x radius.radius=0.194/2=0.097MM.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2000>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The noble gas, argon, is used for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">electric arc welding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">welding brass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">underwater welding</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Steel welding</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Argon is used in electric arc welding because it is an inert gas that does not react with the metal being welded. This prevents oxidation and other chemical reactions that could weaken the weld.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>2000>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A side effect of soft water is that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it gives offensive taste</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess calcium is precipitated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">it attacks lead contained in pipes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it encourage the growth of bacteria</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Soft water is water that has low concentrations of ions, particularly calcium and magnesium. One side effect of soft water is that it can corrode lead pipes, releasing lead into the water.</div>", "topic": "WATER : PURIFICATION OF TOWN WATER SUPPLIES"}, {"id": "objective>Chemistry>2000>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Water molecules can be ligands especially when they are bonded to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkaline earth metals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkali metals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">transition metals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">group VII elements</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Water molecules can act as ligands, or molecules that donate a pair of electrons to a metal ion to form a coordinate bond. This is especially common with transition metals, which often have empty d orbitals that can accept the electron pair.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2000>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The air pollutant unknown to nature is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">HCHO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">DDT</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">DDT (dichlorodiphenyltrichloroethane) is a synthetic chemical that was widely used as an insecticide in the mid-20th century. It is not naturally occurring and is therefore an air pollutant unknown to nature.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2000>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">1.0dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of distilled water was used to wash 2.0g of a precipitate of AgCl. If the solubility product of AgCl is 2.0 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span> mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span>, what quantity of silver was lost in the process? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.029 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.414 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.029 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span> mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.414 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Ag → Ag<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> in the ratio x → x + x  <br/>  sp = x<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> i.e 2.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span> = x<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>  <br/>  x = √ 2.0 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-10</span> moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> = 1.414 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span>moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>2000>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Hydration of ions solution is associated with </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">absorption of heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduction of heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conduction of heat</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liberation of heat</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydration of ions in solution is an exothermic process, meaning it releases heat. This is because the process of hydration involves the formation of bonds between the ions and the water molecules, and bond formation always releases energy.</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>2000>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above is the solubility curve of a solute, X. Find the amount of X deposited when 500cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a solution of X is cooled from 60<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C to 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.750mole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.950mole</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.375moles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.750moles</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Solubility at 60°C = 5.5 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>  <br/>  Solubility at 20°C = 4.0mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>  <br/> 5.5-4.0=1.5 <br/> ∴ 1.5 moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> will be precipitated on cooling 1,000cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of the solution X from 60°C to 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C <br/> Amount of X = concentration * volume/10000 <br/> =1.5 * 500/1000 <br/>  750/1000  <br/> = 0.750mole</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2000>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">HCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">ag</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span> → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span>  <br/>  In the reaction above, Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> is the  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">conjugate acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">conjugate base</div>", "<div style=\"font-family:Cambria;font-size:17px;\">base</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the given reaction, HCl donates a proton to H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O to form H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> and Cl<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>. This makes HCl the acid and Cl- the base. However, since Cl- is formed from the acid (HCl), it is referred to as the conjugate base of the acid.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2000>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In which order are the following salts sensitive to light?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">AgI > AgCl > AgBr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AgCl > AgI > AgBr</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AgBr > AgCI > AgI</div>", "<div style=\"font-family:Cambria;font-size:17px;\">AgCl > AgBr > AgI</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">AgBr > AgCI > AgI <br/> AgBr is used in the production of photographic chemicals</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2000>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The pOH of a solution of 0.25 mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> of hydrochloric acid is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">12.40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">13.40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.40</div>", "<div style=\"font-family:Cambria;font-size:17px;\">14.60</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">pH=-log(H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>) <br/> pH=-log(0.25) <br/> pH=-log(2.5 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>) <br/> =-0.398 + 1=0.602 <br/> pH + pOH=14 <br/> 0.602 + pOH=14 <br/> pOH=14-0.602 <br/> =13.4</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2000>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> + 8H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + Y → Mn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(I)</span>  <br/>  Y in the equation above represents</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">3e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">7e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">-1 + (8 x 1) + y = +2 + (4 x 0) <br/> -1 + 8 +y=2 <br/> 7 +y=2 <br/> y=2-7 <br/> y=5e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span></div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2000>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">1/2 Zn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> → 1/2 Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>  <br/>  In the reaction above, calculate the quantity of electricity required to discharge zinc.  <br/>  [F = 96 500 C mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.965 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.820 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">9.650 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>C</div>", "<div style=\"font-family:Cambria;font-size:17px;\">48.200 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>C</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">1 mole will give 96,500C x 2 <br/>  0.5 mole will give 0.5 × 96,500 × 2 = 9.650 x 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span>C </div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2000>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given that M is the mass of substances deposited in an electrolysis and Q the quantity of electricity consumed, then faraday's law can be written as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">M = Z/Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M = Q/Z</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M = Z/2Q</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M = QZ</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Faraday's law can be written as <br/> M = Zit <br/> recall Q = it <br/> M = QZ.</div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2000>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">0.46g of ethanol when burned raised the temperature of 50g of water by 14.3K. Calculate the heat of combustion of ethanol. [C = 12, O = 16, H = 1, specific heat capacity of water = 4.2 Jg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>K<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">+3000 kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">+300 kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">-300 kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">-3000 kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Heat evolved  = -mcθ <br/> Mass of water = 50g <br/> -50 x 4.2 x 14.3 <br/>  = -3003J <br/> Mass of ethanol = 0.46 <br/> Molar mass of ethanol = 46 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Number</td><td style=\"text-align:center;\">of</td><td style=\"text-align:center;\">moles</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.46<hr size=\"1\" />46</td></tr></table></div> <br/> = 0.01 <br/> 0.01mole of ethanol produced -3003J of heat energy 1 mole of ethanol will produce <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">-3003<hr size=\"1\" />0.01</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-300300J/mol</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Converting</td><td style=\"text-align:center;\">to</td><td style=\"text-align:center;\">kJ</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">-300300<hr size=\"1\" />1000</td></tr></table></div> <br/> = -300.3kJmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>2000>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Powdered marble reacts faster with hydrochloric acid solution than the granular form because the powdered form has</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">more molecule</div>", "<div style=\"font-family:Cambria;font-size:17px;\">more atoms</div>", "<div style=\"font-family:Cambria;font-size:17px;\">large surface area</div>", "<div style=\"font-family:Cambria;font-size:17px;\">relatively large mass</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of a chemical reaction is often increased by increasing the surface area of the reactants. This is because a larger surface area allows for more collisions between reactant particles per unit time. Therefore, powdered marble reacts faster with hydrochloric acid solution than the granular form because the powdered form has a larger surface area.</div>", "topic": "RATE OF CHEMICAL REACTION : FACTORS"}, {"id": "objective>Chemistry>2000>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The graph that describe a zero order reaction is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a zero-order reaction, the reaction rate is independent of the reactant concentration. Therefore, dR/dt=K.s</div>", "topic": "RATE OF CHEMICAL REACTION : CONCENTRATION OR TIME CURVES"}, {"id": "objective>Chemistry>2000>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> → 2NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>; ∆H = + 180.6kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/>  In the reaction above, increase in temperature will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase the quantity of N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase the yield of NO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease the yield of NO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decrease the quantity of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since it is an endothermic reaction, increase in temperature will favour the forward reaction, thereby increasing the yield of NO.</div>", "topic": "CHEMICAL EQUILIBRA : LE CHATELIER'S PRINCIPLE AND EQUILIBRIUM CONSTANT"}, {"id": "objective>Chemistry>2000>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For a reaction in equilibrium, the species involved in the equilibrium constant expression are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gaseous and solid species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquid and solid species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solid and dissolved species</div>", "<div style=\"font-family:Cambria;font-size:17px;\">gaseous and dissolved species</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the expression for the equilibrium constant (K) of a reaction, only the concentrations of gaseous and dissolved species are included. The concentrations of solid and liquid species are not included because their concentrations do not change with the progress of the reaction.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2000>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A phenomenon where an element exist in different forms in the same physical state is known as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">isomerism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">amorphism</div>", "<div style=\"font-family:Cambria;font-size:17px;\">allotropy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isotopy</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Allotropy is the phenomenon where an element exists in different forms in the same physical state. For example, carbon exists as diamond, graphite, and fullerene in the solid state.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE CONCEPT OF ATOMS, MOLECULES AND IONS"}, {"id": "objective>Chemistry>2000>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The substance often used for vulcanization of rubber is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">chlorine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen peroxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tetraoxosulphate (VI) acid</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur is used for the vulcanization of rubber. Vulcanization is a chemical process that converts natural rubber or related polymers into more durable materials by adding sulphur.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2000>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A gas that is not associated with global warming is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> or Hydrogen gas is not associated with global warming. The main gases that cause global warming are carbon dioxide (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>), methane (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>), and nitrous oxide (N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O). Although SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is not a greenhouse gas, it contributes to air pollution and acid rain, which have environmental impacts but it is not directly linked to global warming.</div>", "topic": "ENVIRONMENTAL POLLUTION : AIR POLLUTION"}, {"id": "objective>Chemistry>2000>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The refreshing and characteristic taste of soda water and other soft drinks is as a result of the presence of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide </div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (II) oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">soda </div>", "<div style=\"font-family:Cambria;font-size:17px;\">glucose</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The refreshing and characteristic taste of soda water and other soft drinks is as a result of the presence of carbon (IV) oxide, also known as carbon dioxide (CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>). When dissolved in water, CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> forms a weak acid called carbonic acid which gives the drinks their characteristic taste.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2000>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A form of carbon used for absorbing poisonous gases and purification of noble gases is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wood charcoal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">animal charcoal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon fibres</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon black</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Wood charcoal is used. It is also called Activated Charcoal. </div>", "topic": "NON-METALS AND THEIR COMPOUNDS : CARBON"}, {"id": "objective>Chemistry>2000>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Synthesis gas is a mixture of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O </div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO and H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Synthesis gas, also known as syngas, is a mixture of carbon monoxide (CO) and hydrogen (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>). It is used as an intermediate in producing synthetic petroleum for use as a fuel or lubricant.</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2000>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Potassium vapour burns with a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">blue flame</div>", "<div style=\"font-family:Cambria;font-size:17px;\">brick-red flame</div>", "<div style=\"font-family:Cambria;font-size:17px;\">violet flame</div>", "<div style=\"font-family:Cambria;font-size:17px;\">golden yellow flame</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Potassium vapour burns with a violet flame. This is due to the excitation of electrons in the potassium atoms, which emit light in the violet part of the spectrum when they return to their ground state.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS"}, {"id": "objective>Chemistry>2000>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A common characteristics of copper and silver in their usage as coinage metals is that they </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">have high metallic lustre</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are not easily oxidized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are easily oxidized</div>", "<div style=\"font-family:Cambria;font-size:17px;\">are not easily reduced</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A common characteristic of copper and silver in their usage as coinage metals is that they are not easily oxidized. This means they do not react readily with oxygen to form oxides, which would tarnish their surfaces and decrease their value.</div>", "topic": "METALS AND THEIR COMPOUNDS : COPPER"}, {"id": "objective>Chemistry>2000>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Haematite is an ore of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zinc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lead</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iron</div>", "<div style=\"font-family:Cambria;font-size:17px;\">copper</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Haematite is an ore of iron. An ore is a naturally occurring material from which a mineral or minerals of economic value can be extracted profitably. In this case, iron can be extracted from haematite.</div>", "topic": "METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>2000>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The least easily oxidized of the metals below is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Ca</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Al</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Zinc is lower to the metals in the eletrochemical series in which the oxidizing ability of atoms in the series decreases down the series.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS~~METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2000>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The repeated unit in natural rubber is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkyne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">isoprene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">n-propene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neoprene</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The repeated unit in natural rubber is isoprene. Natural rubber is a polymer of isoprene, also known as 2-methyl-1,3-butadiene, with the chemical formula (C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>)n.</div>", "topic": "ORGANIC COMPOUNDS : GIANT MOLECULES"}, {"id": "objective>Chemistry>2000>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Unsaturated organic compounds are identified by decolourization of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">silver bromine and potassium tetraoxomaganate (VII) solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bromine water and acidified potassium tetraoxomaganate (VII) solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">silver bromine solution and bromine water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">bromine water and alkaline potassium tetramaganate (VII) solution </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Unsaturated organic compounds are identified by decolourization of bromine water and acidified potassium tetraoxomaganate (VII) solution. This is because unsaturated compounds have double or triple bonds that can add bromine (a test for unsaturation) and can be oxidized by potassium tetraoxomaganate (VII), changing its color.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2000>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The conditions necessary for extraction of a water molecule from two molecules of ethanol are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">less acid and lower temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess acid and a lower temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">excess acid and a higher temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less acid and a higher temperature</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The conditions necessary for extraction of a water molecule from two molecules of ethanol are excess acid and a higher temperature. This process is known as dehydration of ethanol, which is a type of elimination reaction.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2000>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The chlorinated alkane often used industrially to remove grease is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tetrachloromethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chloromethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trichloromethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dichloromethane</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The chlorinated alkane often used industrially to remove grease is tetrachloromethane. Tetrachloromethane, also known as carbon tetrachloride, is a solvent for oils, fats, lacquers, varnishes, rubber waxes, and resins.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2000>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction of carbide with water gives</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethyne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanal</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It give ethyne (acetylene gas)  <br/>  CaC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O → C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + CaOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. <br/>  This is a way of producing ethyne in the laboratory <br/> The reaction of carbide with water gives ethyne. Calcium carbide reacts with water to form acetylene (also known as ethyne) and calcium hydroxide.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2000>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The compound above is an </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ether</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ester</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanol</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It is an ester. Esters are chemical compounds derived from an acid (organic or inorganic) in which at least one -OH (hydroxyl) group is replaced by an -O-alkyl (alkoxy) group. Usually, esters are derived from a carboxylic acid and an alcohol.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2000>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Alkanones are generally obtained by the oxidation of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">primary alkanols</div>", "<div style=\"font-family:Cambria;font-size:17px;\">secondary alkanols</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tertiary alkanols </div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanoic acid</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Alkanone or ketones are often prepared by oxidation of secondary alcohols: R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH(OH) + O → R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>C=O + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O. Alkanones are generally obtained by the oxidation of secondary alkanols. Alkanones are a type of ketone, and ketones are produced by the oxidation of secondary alcohols.</div>", "topic": "ORGANIC COMPOUNDS : ALKANONES"}, {"id": "objective>Chemistry>2000>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sucrose is made up of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">glucose and glucose </div>", "<div style=\"font-family:Cambria;font-size:17px;\">glucose and fructose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">fructose and fructose</div>", "<div style=\"font-family:Cambria;font-size:17px;\">galactose and glucose</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sucrose is made up of glucose and fructose. Sucrose is a disaccharide, a molecule composed of two monosaccharides: glucose and fructose.</div>", "topic": "ORGANIC COMPOUNDS : CARBOHYDRATES"}];
